import { mkdir, writeFile } from 'node:fs/promises'
import path from 'node:path'
import { fileURLToPath } from 'node:url'
import redirects from '../redirects.config.mjs'

const GENERATED_COMMENT =
  '# Generated by scripts/generate-redirects.mjs. Do not edit by hand.'

const __filename = fileURLToPath(import.meta.url)
const __dirname = path.dirname(__filename)
const rootDir = path.resolve(__dirname, '..')

function assertSupportedRedirect(redirect) {
  const unsupportedKeys = ['basePath', 'has', 'locale', 'missing', 'statusCode']

  for (const key of unsupportedKeys) {
    if (redirect[key] !== undefined) {
      throw new Error(`Unsupported redirect option "${key}" for ${redirect.source}`)
    }
  }
}

function nextSourceToRedirectSource(source) {
  const wildcardParams = []
  const converted = source.replace(
    /:([A-Za-z0-9_]+)([+*?])?/g,
    (_, name, modifier = '') => {
      if (modifier === '') return `:${name}`

      if (modifier === '*') {
        wildcardParams.push(name)
        return '*'
      }

      throw new Error(`Unsupported redirect token ":${name}${modifier}" in ${source}`)
    }
  )

  if (wildcardParams.length > 1) {
    throw new Error(`Only one splat redirect is supported in ${source}`)
  }

  return {
    source: converted,
    wildcardParam: wildcardParams[0] ?? null,
  }
}

function nextDestinationToRedirectDestination(destination, wildcardParam) {
  if (!wildcardParam) return destination

  return destination.replace(
    new RegExp(`:${wildcardParam}\\*?`, 'g'),
    ':splat'
  )
}

function toRedirectRule(redirect) {
  assertSupportedRedirect(redirect)

  const { source, wildcardParam } = nextSourceToRedirectSource(redirect.source)

  return {
    source,
    destination: nextDestinationToRedirectDestination(
      redirect.destination,
      wildcardParam
    ),
    status: redirect.permanent ? 301 : 302,
  }
}

function renderRedirectsFile(redirectRules) {
  const lines = [GENERATED_COMMENT, '']

  for (const redirect of redirectRules) {
    lines.push(`${redirect.source} ${redirect.destination} ${redirect.status}`)
  }

  return `${lines.join('\n')}\n`
}

async function main() {
  const redirectRules = redirects.map(toRedirectRule)
  const contents = renderRedirectsFile(redirectRules)
  const outputs = [
    path.join(rootDir, 'public', '_redirects'),
    path.join(rootDir, 'out', '_redirects'),
  ]

  for (const filePath of outputs) {
    await mkdir(path.dirname(filePath), { recursive: true })
    await writeFile(filePath, contents)
  }
}

main().catch((error) => {
  console.error(error)
  process.exitCode = 1
})
